// HasItems applies the HasEdge predicate on the "items" edge.
func HasItems() predicate.SalesReturn {
	return predicate.SalesReturn(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ItemsTable, ItemsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasItemsWith applies the HasEdge predicate on the "items" edge with a given conditions (other predicates).
func HasItemsWith(preds ...predicate.SalesReturnItem) predicate.SalesReturn {
	return predicate.SalesReturn(func(s *sql.Selector) {
		step := newItemsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SalesReturn) predicate.SalesReturn {
	return predicate.SalesReturn(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SalesReturn) predicate.SalesReturn {
	return predicate.SalesReturn(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SalesReturn) predicate.SalesReturn {
	return predicate.SalesReturn(sql.NotPredicates(p))
}
